import React, { useState } from 'react';

export default function Login(props) {
    const [errM, setErrM] = useState("")
    const [playerName, setName] = useState("")
    let checkname = (event)=>{
        let name = event.target.value
        setName(name)
        if (name.length==0)
        setErrM("name is too short")
        else
        setErrM("")

    }

    let startTheGame= ()=>{
        if(playerName.length>0){
        props.savePlayerName(playerName)
        props.currentPage(props.pages.game)
    }
        else
        alert("Please fill up your name")
    }
  return (
    <div>
        <h1>Welcome to our game!</h1>
        <file >
            <input type="text" onChange={checkname} placeholder='Please enter your name'/>
            <br></br>   
            <button onClick={startTheGame}>Submit</button>
            <br></br>
            <h3>{errM}</h3>
        </file>

    </div>
  )
}
